SELECT SUM(value) AS total_trade_value
FROM insider_trades
WHERE company_id = (SELECT ticker_id FROM tickers WHERE ticker = 'AAPL');

SELECT filing_date
FROM insider_trades
WHERE ticker = 'TSLA' AND trade_type = 'P - Purchase' AND quantity > 1000;

SELECT SUM(price * quantity) AS total_trade_value
FROM insider_trades
WHERE insider_id = 1;
